#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        char S[N + 1];
        scanf("%s", S);
        while (Q--) {
            int p, k;
            scanf("%d %d", &p, &k);
            int borders[p + 1];
            int count = 0;
            for (int i = 1; i <= p; i++) {
                if (strncmp(S, S + p - i, i) == 0) {
                    borders[count++] = i;
                }
            }
            qsort(borders, count, sizeof(int), compare);
            if (k > count) {
                printf("-1\n");
            } else {
                printf("%d\n", borders[k - 1]);
            }
        }
    }
    return 0;
}

