        cin >> S;
        while (Q--) {
            int p, k;
            cin >> p >> k;
            string prefix = S.substr(0, p);
            set<int> borders;
            for (int i = 1; i <= p; i++) {
                if (prefix.substr(0, i) == prefix.substr(p - i, i)) {
                    borders.insert(i);
                }
            }
            if (k > borders.size()) {
                cout << -1 << endl;
            } else {
                auto it = borders.begin();
                for (int i = 0; i < k - 1; i++) {
                    it++;
                }
                cout << *it << endl;
            }
        }
    }
    return 0;
}

