import java.util.Scanner;
import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            String S = sc.next();
            while (Q-- > 0) {
                int p = sc.nextInt();
                int k = sc.nextInt();
                String prefix = S.substring(0, p);
                int[] borders = new int[p + 1];
                int count = 0;
                for (int i = 1; i <= p; i++) {
                    if (prefix.substring(0, i).equals(prefix.substring(p - i, p))) {
                        borders[count++] = i;
                    }
                }
                Arrays.sort(borders, 0, count);
                if (k > count) {
                    System.out.println(-1);
                } else {
                    System.out.println(borders[k - 1]);
                }
            }
        }
    }
}

